def get_tags_for_quiz(subject: str) -> list[str]:
    for quiz in QUIZZES_DATA:
        if quiz["id"] == subject or quiz["title"] == subject:
            return list(quiz.get("tags", []))
    normalized = subject.lower().replace("_", "-").replace(" ", "-")
    return [normalized]
